import React, { useState } from "react";
import { FaHome, FaUser, FaCog, FaBars, FaTimes, FaEdit, FaTrash } from "react-icons/fa";
import "./dashboardhome.css";

const clients = [
  {
    id: 1,
    image: "https://via.placeholder.com/40",
    name: "John Doe",
    role: "Admin",
    email: "john.doe@example.com"
  },
  {
    id: 2,
    image: "https://via.placeholder.com/40",
    name: "Jane Smith",
    role: "User",
    email: "jane.smith@example.com"
  }
];

const DashboardHome = () => {
  const [isOpen, setIsOpen] = useState(true);

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? "open" : "closed"}`}>
        <button className="toggle-btn" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </button>
        <ul>
          <li>
            <FaHome /> {isOpen && <span>Home</span>}
          </li>
        
          <li>
            <FaCog /> {isOpen && <span>L</span>}
          </li>
        </ul>
      </div>

      {/* Main Content */}
      <div className="dashboard-content">
        <h1>Dashboard Home</h1>
        <p>Welcome to your dashboard.</p>

        {/* Clients & Business Table */}
        <div className="table-container">
          <h2>Clients & Business List</h2>
          <table>
            <thead>
              <tr>
                <th>Image</th>
                <th>Name</th>
                <th>Role</th>
                <th>Email Address</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {clients.map((client) => (
                <tr key={client.id}>
                  <td><img src={client.image} alt={client.name} /></td>
                  <td>{client.name}</td>
                  <td>{client.role}</td>
                  <td>{client.email}</td>
                  <td>
                    <button className="edit-btn"><FaEdit /></button>
                    <button className="delete-btn"><FaTrash /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default DashboardHome;
